  ('heelevel3-e3452428-moex-00046', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-114-3082b5f1', 'sub-heelevel3-e3452428-04', NULL, 'single_choice', '關於公務人員保障法復審規定之敘述，下列何者錯誤？', '["公務人員對於服務機關所為之管理措施認為不當，致影響其權益者，得提起復審", "原處分機關之認定，原則上以實施行政處分時之名義為準", "原處分機關裁撤或改組，應以承受其業務之機關視為原處分機關", "復審之提起，應自行政處分達到之次日起30日內為之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:44+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "201", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般民政"}'::jsonb, NULL),
  ('heelevel3-e3452428-moex-00047', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-114-3082b5f1', 'sub-heelevel3-e3452428-04', NULL, 'single_choice', '關於法規命令之敘述，下列何者錯誤？', '["法規命令須刊登於政府公報或新聞紙，始生效力", "法規命令訂定須經其他機關核准而未核准發布者，效力未定", "訂定法規命令可不經聽證程序", "擬訂法規命令應使人民得陳述意見 21250–21350 22150 22950–23050 23250、23450"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:44+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "201", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般民政"}'::jsonb, NULL),
  ('heelevel3-e3452428-moex-00048', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-114-3082b5f1', 'sub-heelevel3-e3452428-04', NULL, 'single_choice', '關於訴願之期限，下列敘述何者正確？', '["訴願之提起，應於原行政處分機關或受理訴願機關收受訴願書當日起算30日內", "訴願之決定，自收受訴願書之次日起，原則上應於2個月內為之", "訴願決定書應附記，如不服決定，得於決定書送達之次日起1個月內向行政法院提起行政訴訟", "訴願決定書之正本，應於決定後15日內送達訴願人、參加人及原行政處分機關"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:44+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "201", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般民政"}'::jsonb, NULL),
  ('heelevel3-e3452428-moex-00049', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-114-3082b5f1', 'sub-heelevel3-e3452428-04', NULL, 'single_choice', '關於行政處分之效力，下列敘述何者錯誤？', '["已無法再循通常救濟途徑予以變更或撤銷之行政處分，除別有規定外，即產生形式存續力", "行政處分須直到發生形式存續力後，方對相對人及原處分機關產生拘束力", "行政程序法第128條關於行政程序重新進行之規定，係行政處分形式存續力之例外", "違法行政處分於法定救濟期間經過後，原處分機關仍得依職權撤銷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:44+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "201", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般民政"}'::jsonb, NULL),
  ('heelevel3-e3452428-moex-00050', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-114-3082b5f1', 'sub-heelevel3-e3452428-04', NULL, 'single_choice', '下列何者屬於附負擔附款之行政處分？', '["在普通汽車駕駛執照中，附記不得操作大客車", "發給施工許可，但註記施工期間3個月", "主管機關許可舉辦演唱會，但將舉辦方所申請之4小時調整為3小時", "行政機關同意資助公務員出國進修，但進修結束後5年內不得離職"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:44+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "201", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般民政"}'::jsonb, NULL),
